/**
 * Order pricing module.
 *
 * Computes the total price of an order: item subtotal, discounts, VAT, and
 * currency-aware rounding. The public surface is `computePrice` and
 * `PricingFacade`.
 */

export interface OrderItem {
  name: string;
  unitPrice: number;
  quantity: number;
}

export type Currency = "GBP" | "EUR" | "USD";

export interface Order {
  items: OrderItem[];
  currency: Currency;
  loyaltyMember: boolean;
}

class MoneyValue {
  constructor(
    readonly amount: number,
    readonly currency: Currency,
  ) {}

  plus(other: MoneyValue): MoneyValue {
    if (other.currency !== this.currency) {
      throw new Error("cannot add across currencies without conversion");
    }
    return new MoneyValue(this.amount + other.amount, this.currency);
  }
}

type DiscountFn = (order: Order, subtotal: number) => number | null;

const bulkDiscount: DiscountFn = (order, subtotal) => {
  const totalQty = order.items.reduce((sum, item) => sum + item.quantity, 0);
  return totalQty >= 10 ? subtotal * 0.9 : null;
};

const multiLineDiscount: DiscountFn = (order, subtotal) => {
  const distinctNames = new Set(order.items.map(item => item.name));
  return distinctNames.size >= 3 ? subtotal * 0.98 : null;
};

const loyaltyDiscount: DiscountFn = (order, subtotal) => {
  return order.loyaltyMember ? subtotal * 0.95 : null;
};

const DEFAULT_DISCOUNTS: DiscountFn[] = [bulkDiscount, multiLineDiscount, loyaltyDiscount];

export interface PricingHooks {
  beforeStage?(stageName: string): void;
  afterStage?(stageName: string, runningTotal: number): void;
}

export interface PricingOptions {
  vatRate?: number;
  roundingMode?: "half-up";
  locale?: string;
  hooks?: PricingHooks;
}

const DEFAULT_PRICING_OPTIONS = {
  vatRate: 0.2,
  roundingMode: "half-up" as const,
  locale: "en-GB",
};

function resolveOptions(options?: PricingOptions) {
  return {
    ...DEFAULT_PRICING_OPTIONS,
    ...(options ?? {}),
    hooks: options?.hooks ?? {},
  };
}

function roundToTwoDp(value: number): number {
  return Math.round(value * 100) / 100;
}

function computeSubtotal(order: Order): MoneyValue {
  return order.items.reduce(
    (sum, item) => sum.plus(new MoneyValue(item.unitPrice * item.quantity, order.currency)),
    new MoneyValue(0, order.currency),
  );
}

function applyDiscounts(order: Order, subtotal: number): number {
  let result = subtotal;
  for (const discount of DEFAULT_DISCOUNTS) {
    const adjusted = discount(order, result);
    if (adjusted !== null) {
      result = adjusted;
    }
  }
  return result;
}

function runStage(
  stageName: string,
  amount: number,
  fn: (amount: number) => number,
  hooks: PricingHooks,
): number {
  hooks.beforeStage?.(stageName);
  const result = fn(amount);
  hooks.afterStage?.(stageName, result);
  return result;
}

function runPricingPipeline(order: Order, options: ReturnType<typeof resolveOptions>): number {
  let amount = computeSubtotal(order).amount;
  amount = runStage("discount", amount, a => applyDiscounts(order, a), options.hooks);
  amount = runStage("tax", amount, a => a * (1 + options.vatRate), options.hooks);
  amount = runStage("rounding", amount, roundToTwoDp, options.hooks);
  return amount;
}

// Facade
export class PricingFacade {
  private readonly options: ReturnType<typeof resolveOptions>;

  constructor(options?: PricingOptions) {
    this.options = resolveOptions(options);
  }

  price(order: Order): number {
    return runPricingPipeline(order, this.options);
  }
}

export function computePrice(order: Order, options?: PricingOptions): number {
  return new PricingFacade(options).price(order);
}

